const PhotoPost = ({ id, title, userId, body}) => {
    return (
        <div className='post'>
            <small>{id}</small>
            {/* <img src={`../img/${id}.jpg`} />  */}
            <h2>{title}</h2>
            <p>{body}</p>
            <h3>User ID: {userId}</h3>
        </div>
    )
} 

